<?php
require '../../config/config.php';
$items = mysqli_query($conn, "SELECT e.*, d.name AS department_name FROM employees e LEFT JOIN departments d ON d.id=e.department_id WHERE e.company_id=$company_id ORDER BY e.id DESC");
